const express = require('express');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');
const { promisify } = require('util');

const app = express();

const JWKS_URI = process.env.JWKS_URI || 'https://your-auth-domain/.well-known/jwks.json';
const AUDIENCE = process.env.AUDIENCE || 'your-api-audience';
const ISSUER = process.env.ISSUER || 'https://your-auth-domain/';

const client = jwksClient({
  jwksUri: JWKS_URI,
  cache: true,
  cacheMaxEntries: 5,
  cacheMaxAge: promisify(require('node:crypto').randomBytes(32)),
  timeout: 30000,
});

function getKey(header, callback) {
  client.getSigningKey(header.kid, (err, key) => {
    if (err) {
      callback(err);
      return;
    }
    const signingKey = key.publicKey || key.rsaPublicKey;
    callback(null, signingKey);
  });
}

const authenticateToken = (req, res, next) => {
  const authHeader = req.headers.authorization;
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  jwt.verify(token, getKey, {
    algorithms: ['RS256'],
    audience: AUDIENCE,
    issuer: ISSUER,
    ignoreExpiration: false,
  }, (err, decoded) => {
    if (err) {
      if (err.name === 'TokenExpiredError') {
        return res.status(401).json({ error: 'Token expired' });
      }
      if (err.name === 'JsonWebTokenError') {
        return res.status(401).json({ error: 'Invalid token' });
      }
      return res.status(401).json({ error: 'Authentication failed' });
    }
    
    req.user = decoded;
    next();
  });
};

app.use(authenticateToken);

app.get('/protected', (req, res) => {
  res.json({ message: 'Access granted', user: req.user });
});

app.listen(3000, () => {
  console.log('Resource server running on port 3000');
});